import React, { useState, useRef, useEffect } from 'react';

function ChatBot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { text: "Hi! I'm CampusBot 🤖. How can I help you today?", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const messagesEndRef = useRef(null);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = () => {
    if (!input.trim()) return;

    // 1. Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    
    // 2. Generate Bot Response (Keyword Logic)
    setTimeout(() => {
      let botResponse = "I'm not sure about that. Try asking about 'upload', 'size', or 'admin'.";
      const lowerInput = input.toLowerCase();

      if (lowerInput.includes("hello") || lowerInput.includes("hi")) {
        botResponse = "Hello! 👋 Ready to upload a project?";
      } else if (lowerInput.includes("upload") || lowerInput.includes("submit")) {
        botResponse = "To upload, click the '+' button in the top right corner. Make sure you are logged in!";
      } else if (lowerInput.includes("size") || lowerInput.includes("mb")) {
        botResponse = "⚠️ Image files must be less than 1MB. Use a compressor tool if your file is too big.";
      } else if (lowerInput.includes("admin") || lowerInput.includes("approve")) {
        botResponse = "Admins usually review projects within 24 hours. You will see the status change on your profile.";
      } else if (lowerInput.includes("thank")) {
        botResponse = "You're welcome! Good luck with your project! 🎓";
      }

      setMessages((prev) => [...prev, { text: botResponse, isBot: true }]);
    }, 600); // Small delay to feel "real"

    setInput("");
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">
      
      {/* CHAT WINDOW */}
      {isOpen && (
        <div className="bg-white w-80 h-96 rounded-2xl shadow-2xl border border-gray-200 flex flex-col overflow-hidden animate-fade-in-up mb-4">
          
          {/* Header */}
          <div className="bg-indigo-600 p-4 flex justify-between items-center text-white">
            <div className="flex items-center gap-2">
              <span className="text-2xl">🤖</span>
              <h3 className="font-bold">CampusBot</h3>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-indigo-700 w-8 h-8 rounded-full">✕</button>
          </div>

          {/* Messages Area */}
          <div className="flex-1 p-4 overflow-y-auto bg-gray-50 space-y-3">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[80%] p-3 rounded-xl text-sm ${
                  msg.isBot 
                    ? 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm' 
                    : 'bg-indigo-600 text-white rounded-tr-none shadow-md'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-3 border-t bg-white flex gap-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask for help..." 
              className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button 
              onClick={handleSend}
              className="bg-indigo-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-700 transition"
            >
              ➤
            </button>
          </div>
        </div>
      )}

      {/* FLOATING BUTTON */}
      {!isOpen && (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full shadow-lg shadow-indigo-500/40 flex items-center justify-center text-3xl transition-transform hover:scale-110 active:scale-95"
        >
          🤖
        </button>
      )}
    </div>
  );
}

export default ChatBot;
